func (c *current) onCaseExpr2(cases, else_ any) (any, error) {
	whens := sliceOf[ast.When](cases)
	cond := &ast.CondExpr{
		Kind: "CondExpr",
		Cond: whens[0].Cond,
		Then: whens[0].Then,
		Loc:  loc(c),
	}
	last := cond
	for _, when := range whens[1:] {
		next := &ast.CondExpr{
			Kind: "CondExpr",
			Cond: when.Cond,
			Then: when.Then,
			Loc:  when.Loc,
		}
		last.Else = next
		last = next
	}
	if else_ != nil {
		last.Else = else_.([]any)[3].(ast.Expr)
	}
	return cond, nil

}

